// Convertir le fichier binaire reçu en base64
const binaryData = $input.first().binary;

if (!binaryData) {
  throw new Error('Aucun fichier reçu. Envoyez une image.');
}

const binaryKey = Object.keys(binaryData)[0];
const fileBuffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const base64Image = fileBuffer.toString('base64');
const mimeType = binaryData[binaryKey].mimeType;
const fileName = binaryData[binaryKey].fileName || 'document';

return [{
  json: {
    base64Image,
    mimeType,
    fileName
  }
}];

const response = $input.first().json;
const text = response.response || '';

// Extraire le JSON de la réponse
const firstBrace = text.indexOf('{');
const lastBrace = text.lastIndexOf('}');

if (firstBrace === -1 || lastBrace === -1) {
  return [{ json: { success: false, error: 'JSON non trouvé', raw: text.substring(0, 500) } }];
}

let jsonStr = text.substring(firstBrace, lastBrace + 1);

let data;
try {
  data = JSON.parse(jsonStr);
} catch (e) {
  // Tenter de corriger les virgules trailing
  jsonStr = jsonStr.replace(/,\s*([}\]])/g, '$1');
  try {
    data = JSON.parse(jsonStr);
  } catch (e2) {
    return [{ json: { success: false, error: 'JSON invalide: ' + e2.message, raw: jsonStr.substring(0, 500) } }];
  }
}

const fileName = $('Code Base64').first().json.fileName || 'unknown';

// Préparer les warnings
const warnings = [];
if (!data.fournisseur?.nom) warnings.push('Nom fournisseur manquant');
if (!data.facture?.numero) warnings.push('Numéro facture manquant');
if (!data.articles || data.articles.length === 0) warnings.push('Aucun article');
if (data.totaux?.total_ttc == null) warnings.push('Total TTC manquant');

return [{
  json: {
    success: true,
    extraction: data,
    metadata: {
      source_file: fileName,
      extraction_date: new Date().toISOString(),
      model_used: 'moondream',
      validation_warnings: warnings,
      is_valid: warnings.length === 0,
      nombre_articles: data.articles?.length || 0
    }
  }
}];
